import os
from langchain import OpenAI, VectorDBRetriever
from langchain.chains import RetrievalQA
from langchain.document_loaders import DirectoryLoader
from langchain.embeddings import OpenAIEmbeddings
from langchain.vectorstores import FAISS

# Load company documents into vector database
def load_documents(directory):
    loader = DirectoryLoader(directory, glob="*.pdf")
    documents = loader.load()
    embeddings = OpenAIEmbeddings()
    vectorstore = FAISS.from_documents(documents, embeddings)
    return vectorstore

# Create RAG system
def create_rag_system(vectorstore):
    retriever = VectorDBRetriever(vectorstore=vectorstore, k=3)
    llm = OpenAI(model_name="text-davinci-003")
    rag_chain = RetrievalQA.from_llm(llm, retriever=retriever)
    return rag_chain

# Accept user queries and retrieve relevant context
def query_rag_system(rag_chain, query):
    response = rag_chain.run(query)
    return response

# Main function to run the RAG system
def main():
    directory = "path/to/company/documents"
    vectorstore = load_documents(directory)
    rag_chain = create_rag_system(vectorstore)

    while True:
        user_query = input("User: ")
        if user_query.lower() in ["exit", "quit"]:
            break
        response = query_rag_system(rag_chain, user_query)
        print(f"Bot: {response}")

if __name__ == "__main__":
    main()